const rows = $input.all();
const totalEsperado = 17; // Tu número de entornos totales
const pendientes = rows.filter(r => r.json.Estado === 'PENDIENTE');
const oks = rows.filter(r => r.json.Estado === 'OK');

// Escenario 1: No hay nada escrito hoy (Fallo total antes de empezar)
if (rows.length === 0) {
    return { escenario: 'EJECUTAR_PRINCIPAL', motivo: 'No hay registros de hoy' };
}

// Escenario 2: Todos están pendientes (Murió justo después de inicializar)
if (pendientes.length === rows.length && rows.length > 0) {
    return { escenario: 'EJECUTAR_PRINCIPAL', motivo: 'Todo pendiente, relanzar desde cero' };
}

// Escenario 3: Hay algunos OK y algunos PENDIENTES (Murió a la mitad)
if (pendientes.length > 0 && oks.length > 0) {
    return { 
        escenario: 'EJECUTAR_ERROR_HANDLER', 
        pendientes: pendientes.map(p => p.json),
        motivo: `Faltan ${pendientes.length} entornos` 
    };
}

// Escenario 4: Todos están OK
if (oks.length >= totalEsperado) {
    return { escenario: 'DETENER', motivo: 'Todo completado con éxito' };
}

return { escenario: 'EJECUTAR_PRINCIPAL', motivo: 'No se ejecutó el flujo.' };

